static void run_kicked_evolution_test() {
    std::cout << "\n=== Kicked Real-Time Evolution (N=2, delta interaction) ===" << std::endl;

    int N = 2;
    int K_max = 15;

    // Build basis via SVM with kinetic + harmonic + delta
    HamiltonianTerms terms_free;
    terms_free.kinetic  = true;
    terms_free.harmonic = true;
    terms_free.delta    = true;
    terms_free.gaussian = false;
    terms_free.kicking  = false;

    std::cout << "--- Building basis with SVM ---" << std::endl;
    double E_lower_kicked = N * 0.5;  // harmonic trap lower bound
    auto svm = svm_build_basis(N, K_max, 5000, terms_free, 42, E_lower_kicked);
    double E_svm = lowest_energy(svm.H, svm.S);
    std::cout << "SVM ground state E = " << std::setprecision(10) << E_svm << std::endl;

    // Refine basis
    PermutationSet perms = PermutationSet::generate(N);
    auto refined = stochastic_refine(svm.basis, svm.H, svm.S,
                                      perms, N, terms_free, 500, 10, 123,
                                      E_lower_kicked);
    double E_ref = lowest_energy(refined.H, refined.S);
    std::cout << "Refined ground state E = " << std::setprecision(10) << E_ref << std::endl;

    // Set u from eigenvector
    set_u_from_eigenvector(refined.basis, refined.H, refined.S);

    // TDVP imaginary-time polish
    SolverConfig config;
    config.lambda_C  = 1e-8;
    config.rcond     = 1e-4;
    config.resolve_u = true;
    config.dtao_grow = 1.5;

    int basis_n = static_cast<int>(refined.basis.size());
    auto alpha_z_list = build_alpha_z_list(basis_n, N, config);

    std::cout << "\n--- Imaginary-time TDVP polish ---" << std::endl;
    evolution(alpha_z_list, refined.basis, 1, 100, 1e-10, terms_free, config, &perms);

    // Now do kicked real-time evolution
    HamiltonianTerms terms_kick = terms_free;
    terms_kick.kicking = true;

    KickParams kick_params;
    kick_params.T_period   = 1.0;
    kick_params.T_pulse    = 0.0;   // ideal delta kick
    kick_params.kappa_kick = 1.0;
    kick_params.k_L_kick   = 0.5;
    kick_params.n_kicks    = 10;

    SolverConfig rt_config;
    rt_config.lambda_C  = 1e-8;
    rt_config.rcond     = 1e-4;
    rt_config.resolve_u = true;

    double dt_step = 0.01;

    std::cout << "\n--- Real-time kicked evolution ---" << std::endl;
    std::cout << "T_period=" << kick_params.T_period
              << ", n_kicks=" << kick_params.n_kicks
              << ", dt=" << dt_step << std::endl;

    auto obs = kicked_evolution(refined.basis, alpha_z_list, kick_params,
                                 dt_step, terms_free, terms_kick,
                                 rt_config, &perms);

    // Summary
    std::cout << "\n--- Observable summary ---" << std::endl;
    std::cout << std::setw(6) << "kick" << std::setw(12) << "time"
              << std::setw(16) << "energy" << std::setw(16) << "kinetic"
              << std::setw(12) << "overlap" << std::endl;
    for (size_t i = 0; i < obs.size(); i++) {
        std::cout << std::setw(6) << i
                  << std::setw(12) << std::setprecision(4) << obs[i].time
                  << std::setw(16) << std::setprecision(8) << obs[i].energy
                  << std::setw(16) << std::setprecision(8) << obs[i].kinetic_energy
                  << std::setw(12) << std::setprecision(6) << obs[i].overlap_norm
                  << std::endl;
    }
}

// N=2, gamma=0 kicked dynamics: ECG+TDVP vs exact finite-difference
static void run_kicked_gamma0_test() {
    std::cout << "\n=== Kicked Dynamics: N=2, gamma=0 (ECG+TDVP) ===" << std::endl;

    int N = 2;
    int K_max = 10;
    int n_kicks = 5;
    double dt_step = 0.01;

    // Free Hamiltonian: kinetic + harmonic only (no interaction)
    HamiltonianTerms terms_free;
    terms_free.kinetic  = true;
    terms_free.harmonic = true;
    terms_free.delta    = false;
    terms_free.gaussian = false;
    terms_free.kicking  = false;

    // --- Phase 1: SVM basis construction (static mode: B=0, R=0) ---
    std::cout << "\n--- Phase 1: SVM basis (B=0, R=0) ---" << std::endl;
    double E_lower = N * 0.5;  // harmonic ground state
    auto svm = svm_build_basis(N, K_max, 5000, terms_free, 42, E_lower);
    double E_svm = lowest_energy(svm.H, svm.S);
    std::cout << "SVM ground state E = " << std::setprecision(10) << E_svm
              << "  (exact = " << N * 0.5 << ")" << std::endl;

    // --- Phase 1.5: Refinement ---
    PermutationSet perms = PermutationSet::generate(N);
    auto refined = stochastic_refine(svm.basis, svm.H, svm.S,
                                      perms, N, terms_free, 500, 5, 123, E_lower);
    set_u_from_eigenvector(refined.basis, refined.H, refined.S);
    double E_ref = lowest_energy(refined.H, refined.S);
    std::cout << "Refined ground state E = " << std::setprecision(10) << E_ref << std::endl;

    // --- Phase 2: Imaginary-time TDVP polish (static mode) ---
    SolverConfig static_config = SolverConfig::defaults();
    int basis_n = static_cast<int>(refined.basis.size());
    auto alpha_z_static = build_alpha_z_list(basis_n, N, static_config);

    std::cout << "\n--- Phase 2: Imaginary-time TDVP polish ---" << std::endl;
    evolution(alpha_z_static, refined.basis, 1, 50, 1e-10, terms_free, static_config, &perms);

    auto [H_check, S_check] = build_HS(refined.basis, perms, terms_free);
    double E_polished = lowest_energy(H_check, S_check);
    std::cout << "Polished ground state E = " << std::setprecision(10) << E_polished << std::endl;

    // --- Phase 3: Real-time kicked evolution ---
    // Use analytic kick (exact projection) + TDVP free evolution
    double T_period = 1.0;
    double kappa_val = 1.0;
    double k_L_val = 0.5;

    // Static mode for now (A params only, ~30 params vs 80 in dynamics)
    // B and R start at zero and analytic kick only modifies u, not nonlinear params
    SolverConfig rt_config;
    auto alpha_z_dyn = build_alpha_z_list(basis_n, N, rt_config);

    std::cout << "\n--- Phase 3: Real-time kicked evolution (analytic kick) ---" << std::endl;
    std::cout << "T_period=" << T_period
              << ", n_kicks=" << n_kicks
              << ", dt=" << dt_step
              << ", kappa=" << kappa_val
              << ", k_L=" << k_L_val
              << ", params=" << alpha_z_dyn.size() << " (dynamics mode)"
              << std::endl;

    // Collect observables
    struct Obs { double time, energy, kinetic, norm; };
    std::vector<Obs> obs;

    // Record initial state
    {
        Cd E = compute_total_energy(refined.basis, terms_free);
        Cd S = overlap(refined.basis);
        Cd T = kinetic_energy_functional(refined.basis);
        double norm = S.real();
        obs.push_back({0.0, E.real(), (T/S).real(), norm});
        std::cout << "Kick  0: t=0, E=" << std::setprecision(8) << E.real()
                  << ", T=" << (T/S).real() << ", S=" << std::setprecision(6) << norm << std::endl;
    }

    double current_time = 0.0;
    for (int n = 0; n < n_kicks; n++) {
        // 1. Apply analytic kick (instantaneous, exact projection)
        apply_analytic_kick(refined.basis, perms, kappa_val, k_L_val);

        // Diagnostic: energy right after kick, before free evolution
        {
            Cd Ek = compute_total_energy(refined.basis, terms_free);
            Cd Sk = overlap(refined.basis);
            std::cout << "  [post-kick] E=" << std::setprecision(8) << Ek.real()
                      << ", S=" << std::setprecision(6) << Sk.real() << std::endl;
        }

        // 2. Free evolution for one period using TDVP
        free_evolve(refined.basis, alpha_z_dyn, dt_step, T_period,
                    terms_free, rt_config, &perms);
        current_time += T_period;

        // 3. Record observables
        Cd E = compute_total_energy(refined.basis, terms_free);
        Cd S = overlap(refined.basis);
        Cd T = kinetic_energy_functional(refined.basis);
        double norm = S.real();
        obs.push_back({current_time, E.real(), (T/S).real(), norm});
        std::cout << "Kick " << std::setw(2) << (n+1)
                  << ": t=" << std::setprecision(4) << current_time
                  << ", E=" << std::setprecision(8) << E.real()
                  << ", T=" << std::setprecision(8) << (T/S).real()
                  << ", S=" << std::setprecision(6) << norm << std::endl;
    }

    // --- Also run exact for comparison ---
    std::cout << "\n--- Exact reference (finite difference) ---" << std::endl;
    auto exact = kicked_exact_1particle(1.0, 1.0, k_L_val, kappa_val,
                                         T_period, n_kicks);

    // --- Comparison table ---
    std::cout << "\n--- Comparison: ECG vs Exact ---" << std::endl;
    std::cout << std::setw(6) << "kick"
              << std::setw(14) << "E_ECG"
              << std::setw(14) << "E_exact"
              << std::setw(14) << "error"
              << std::setw(14) << "rel_error"
              << std::setw(12) << "norm" << std::endl;

    for (int n = 0; n <= n_kicks; n++) {
        double E_ecg = obs[n].energy;
        double E_ex = 2.0 * exact.kick_energies[n];
        double err = E_ecg - E_ex;
        double rel = std::abs(err) / std::abs(E_ex);
        std::cout << std::setw(6) << n
                  << std::setw(14) << std::setprecision(8) << E_ecg
                  << std::setw(14) << std::setprecision(8) << E_ex
                  << std::setw(14) << std::scientific << err
                  << std::setw(14) << rel
                  << std::setw(12) << std::fixed << std::setprecision(6) << obs[n].norm
                  << std::defaultfloat << std::endl;
    }
}

int main(int argc, char* argv[]) {
    std::cout << std::setprecision(18);

    std::vector<BasisParams> basis;
    int N = 2, basis_n = 2;

    if (argc >= 5 && std::string(argv[1]) == "--csv") {
        std::string filename = argv[2];
        N = std::stoi(argv[3]);
        basis_n = std::stoi(argv[4]);
        basis = load_basis_from_csv(filename, N, basis_n);
        if (basis.empty()) return 1;
    } else {
        for (int t = 0; t < basis_n; t++) {
            basis.push_back(BasisParams::randoman(N, t, t));
        }
    }

    std::cout << "N=" << N << ", K=" << basis_n << std::endl;

    run_phase1(basis, N);

    if (basis_n >= 2) {
        run_phase2(basis, N);
    }

    run_phase3_gradient(basis, N);

    // If invoked with --tdvp flag, run TDVP evolution
    bool run_tdvp = false;
    bool tdvp_only = false;
    bool run_delta = false;
    bool run_gaussian = false;
    bool run_kicking = false;
    bool run_kicked = false;
    bool run_kicked_exact = false;
    bool run_kicked_gamma0 = false;
    for (int i = 1; i < argc; i++) {
        if (std::string(argv[i]) == "--tdvp") run_tdvp = true;
        if (std::string(argv[i]) == "--tdvp-only") tdvp_only = true;
        if (std::string(argv[i]) == "--delta") run_delta = true;
        if (std::string(argv[i]) == "--gaussian") run_gaussian = true;
        if (std::string(argv[i]) == "--kicking") run_kicking = true;
        if (std::string(argv[i]) == "--kicked") run_kicked = true;
        if (std::string(argv[i]) == "--kicked-exact") run_kicked_exact = true;
        if (std::string(argv[i]) == "--kicked-gamma0") run_kicked_gamma0 = true;
    }
    if (run_tdvp || tdvp_only) {
        run_phase3_tdvp();
    }
    if (run_delta) {
        run_phase3_tdvp_delta();
    }
    if (run_gaussian) {
        run_phase3_tdvp_gaussian();
    }
    if (run_kicking) {
        run_phase3_tdvp_kicking();
    }
    if (run_kicked) {
        run_kicked_evolution_test();
    }
    if (run_kicked_exact) {
        run_kicked_exact_test(50);
    }
    if (run_kicked_gamma0) {
        run_kicked_gamma0_test();
    }

    return 0;
}
